#!/usr/bin/env node
import { cpSync, existsSync, mkdirSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const extensionDir = join(repoRoot, "extensions", "vscode-brass-agent");
const distDir = join(repoRoot, "dist");
const bundledDir = join(extensionDir, "bundled");
const bundledDistDir = join(bundledDir, "dist");
const cliEntrypoint = join(distDir, "agent", "cli", "main.cjs");

if (!existsSync(cliEntrypoint)) {
  throw new Error(`Built brass-agent CLI not found: ${cliEntrypoint}. Run npm run build first.`);
}

rmSync(bundledDir, { recursive: true, force: true });
mkdirSync(bundledDir, { recursive: true });
cpSync(distDir, bundledDistDir, { recursive: true });
writeFileSync(
  join(bundledDir, "README.md"),
  [
    "# Bundled brass-agent CLI",
    "",
    "This folder is generated by `scripts/prepare-vscode-bundle.mjs` before packaging the VS Code extension.",
    "It lets the extension run Brass Agent from any VS Code workspace without requiring a global `npm link`.",
    "Do not edit these files by hand.",
    "",
  ].join("\n"),
  "utf8"
);

console.log(`Bundled brass-agent CLI into ${bundledDistDir}`);
